/**
 * Zona — Bloque de Concorde (Voyager DS)
 *
 * Zona de usuario (Header logueado + contenido blanco):
 *   · UserProfileCard — saludo, riesgo, puntos VMC, accesos
 *   · 2 columnas: WalletBalanceCard (Billetera) · ActivityCard (Tu actividad)
 *   · Secondary banner (placeholder)
 *   · OfferShelf «Recomendados» · OfferShelf «Me interesa» (4 OfferCards c/u)
 *   · Centro de ayuda banner (placeholder)
 *
 * Bloque = composición de componentes existentes (reusa el bloque Header).
 */

import type { CSSProperties, JSX } from "react";
import AppHeader from "@/concorde/bloques/header/desktop/Header";
import UserProfileCard from "@/concorde/components/UserProfileCard";
import WalletBalanceCard from "@/concorde/components/WalletBalanceCard";
import ActivityCard from "@/concorde/components/ActivityCard";
import OfferShelf from "@/concorde/components/OfferShelf";
import { ZONA_WIDTH, ZONA_HEIGHT } from "./dimensions";

export { ZONA_WIDTH, ZONA_HEIGHT } from "./dimensions";

export interface ZonaProps {
  /** Usuario logueado — alimenta el CTA del header y el saludo de la card. */
  username?: string;
  className?: string;
}

// Banner placeholder gris 766×100 (igual que en Homepage) — secondary / centro de ayuda.
const BANNER_PLACEHOLDER: CSSProperties = {
  width: 766,
  height: 100,
  borderRadius: 8,
  background: "#E9EAEC",
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
  fontSize: 13,
  fontWeight: 600,
  letterSpacing: "0.06em",
  color: "#9AA1AC",
};

export default function Zona({ username = "ZAEX5G", className = "" }: ZonaProps): JSX.Element {
  return (
    <div
      className={className}
      data-block="zona"
      style={{
        width: ZONA_WIDTH,
        minHeight: ZONA_HEIGHT,
        background: "#ffffff",
        display: "flex",
        flexDirection: "column",
        overflow: "hidden",
        fontFamily: 'var(--vmc-font-display, "Plus Jakarta Sans", -apple-system, sans-serif)',
      }}
    >
      <AppHeader width={ZONA_WIDTH} username={username} />

      {/* Área blanca: columna de 766 (16px a cada lado = 798), gap 16 entre secciones */}
      <div style={{ flex: 1, padding: "24px 16px", display: "flex", justifyContent: "center" }}>
        <div style={{ width: 766, display: "flex", flexDirection: "column", gap: 16 }}>
          {/* Tarjeta de perfil */}
          <UserProfileCard username={username} />

          {/* 2 columnas — Billetera (izq) · Tu actividad (der) */}
          <div style={{ display: "flex", gap: 16 }}>
            <WalletBalanceCard />
            <ActivityCard />
          </div>

          {/* Secondary banner */}
          <div data-slot="secondary-banner" style={BANNER_PLACEHOLDER}>
            SECONDARY BANNER
          </div>

          {/* Estantes de ofertas — Recomendados / Me interesa */}
          <OfferShelf title="RECOMENDADOS" offersLabel="4 Ofertas" />
          <OfferShelf title="ME INTERESA" offersLabel="4 Ofertas" />

          {/* Centro de ayuda banner */}
          <div data-slot="help-banner" style={BANNER_PLACEHOLDER}>
            CENTRO DE AYUDA
          </div>
        </div>
      </div>
    </div>
  );
}

/**
 * Dimensiones del bloque ZonaMobile — módulo plano sin "use client".
 */

export const ZONA_MOBILE_WIDTH = 420;
export const ZONA_MOBILE_HEIGHT = 2059;

"use client";

/**
 * ZonaMobile — Bloque de Concorde (Voyager DS)
 *
 * Zona de usuario · mobile (420 de ancho):
 *   · Header 420×64 logueado → «Bienvenido, ZAEX5G»
 *   · UserProfileCard mobile 388×132 (2 filas: saludo + stats)
 *   · WalletBalanceCard mobile 388×206 (botón CTA morado)
 *   · ActivityCard mobile 388×221 (grid 2×2 de pills)
 *   · Banner secundario 388×120
 */

import type { JSX } from "react";
import { useState } from "react";
import AppHeader from "../../header/desktop/Header";
import AvatarZone from "../../../components/AvatarZone";
import StarIcon from "../../../components/StarIcon";
import InfoIcon from "../../../components/InfoIcon";
import ProfileButton from "../../../components/ProfileButton";
import WalletBalanceCard from "../../../components/WalletBalanceCard";
import ActivityCard from "../../../components/ActivityCard";
import CardTitle from "../../../components/CardTitle";
import OfferCard from "../../../components/OfferCard";
import BadgeStatus from "../../../components/BadgeStatus";
import SidebarMobile, { SidebarMenuButton } from "../../sidebar/mobile/SidebarMobile";

import { ZONA_MOBILE_WIDTH, ZONA_MOBILE_HEIGHT } from "./dimensions";
export { ZONA_MOBILE_WIDTH, ZONA_MOBILE_HEIGHT } from "./dimensions";

const ZM_STYLES = `
/* WalletBalanceCard — override mobile (388×206, botón morado) */
.zm-wallet.wbc { width: 388px; height: 206px; border-radius: 8px; }
/* ActivityCard — override mobile (388×221) */
.zm-activity.actcard { width: 388px; border-radius: 8px; }
.zm-wallet .wbc__acquire {
  background-image:
    linear-gradient(159deg, #8460E5 0%, #3B1782 100%),
    linear-gradient(135deg, #CFBAFF 0%, #FFFFFF 35%, #AE8EFF 65%, #CFBAFF 100%);
  box-shadow: rgba(255,255,255,0.22) 0 1px 0 2px inset, rgba(132,96,229,0.3) 0 2px 8px;
}
.zm-wallet .wbc__acquire:hover {
  box-shadow: rgba(255,255,255,0.2) 0 1px 0 2px inset, rgba(132,96,229,0.4) 0 8px 24px, rgba(132,96,229,0.25) 0 4px 10px;
}
/* Texto degradado "¡Hola, {username}!" */
.zm-greeting {
  background: linear-gradient(90deg, #ED8936 0%, #ED8936 40%, #8460E5 100%);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  font-size: 16px;
  font-weight: 700;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}
.zm-stat-label {
  font-size: 10px;
  font-weight: 500;
  color: #9AA1AC;
  letter-spacing: 0.04em;
  text-transform: uppercase;
}
.zm-stat-value {
  font-size: 13px;
  font-weight: 700;
  color: #ED8936;
  margin-top: 2px;
}
.zm-pts {
  display: flex;
  align-items: center;
  gap: 4px;
  font-size: 13px;
  font-weight: 700;
  color: #3B1782;
  margin-top: 2px;
}
/* Mobile OfferShelf — 388px wide, grid 2×2 de OfferCards 170×232 */
.zm-shelf {
  width: 388px;
  box-sizing: border-box;
  background: #ffffff;
  border-radius: 8px;
  box-shadow: 0 0 8px 4px rgba(0,0,0,0.08);
  padding: 20px 16px 16px;
  display: flex;
  flex-direction: column;
  gap: 16px;
}
.zm-shelf__grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 16px;
}
`;

export interface ZonaMobileProps {
  username?: string;
  className?: string;
  /** Alto del marco para previsualizaciones (px). En producción se omite. Ver `SidebarMobile`. */
  frameHeight?: number;
}

export default function ZonaMobile({ username = "ZAEX5G", className = "", frameHeight }: ZonaMobileProps): JSX.Element {
  const [menuOpen, setMenuOpen] = useState(false);

  const page = (
    <div
      className={className}
      data-block="zona-mobile"
      style={{
        width: ZONA_MOBILE_WIDTH,
        background: "#ffffff",
        display: "flex",
        flexDirection: "column",
        fontFamily: "var(--vmc-font-display, 'Plus Jakarta Sans', -apple-system, sans-serif)",
      }}
    >
      <style suppressHydrationWarning dangerouslySetInnerHTML={{ __html: ZM_STYLES }} />

      {/* Header 420×64 — logueado → "Bienvenido, ZAEX5G" */}
      <AppHeader
        width={ZONA_MOBILE_WIDTH}
        username={username}
        logo={
          <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
            <SidebarMenuButton onClick={() => setMenuOpen(true)} expanded={menuOpen} />
            <img src="/logo-preview.png" alt="VMC Subastas" style={{ height: 26, width: "auto", display: "block" }} />
          </div>
        }
      />

      {/* Contenido a 16px de margen */}
      <div style={{ display: "flex", flexDirection: "column", gap: 16, padding: 16 }}>

        {/* UserProfileCard mobile — 388×132 */}
        <div
          style={{
            width: 388,
            boxSizing: "border-box",
            background: "#ffffff",
            borderRadius: 8,
            boxShadow: "0 0 8px 4px rgba(0,0,0,0.08)",
            padding: 16,
            display: "flex",
            flexDirection: "column",
          }}
        >
          {/* Row 1 (356×40): avatar + saludo + "Ir al Perfil" */}
          <div style={{ display: "flex", alignItems: "center", gap: 8, height: 40 }}>
            <AvatarZone />
            <span className="zm-greeting" style={{ flex: 1, minWidth: 0 }}>¡Hola, {username}!</span>
            <ProfileButton>Ir al Perfil</ProfileButton>
          </div>

          {/* Divider */}
          <div style={{ height: 1, background: "#E1E3E2", margin: "8px 0" }} />

          {/* Row 2 (356×44): stats izquierda + "Historial" derecha */}
          <div style={{ display: "flex", alignItems: "center", height: 44 }}>
            <div style={{ display: "flex", alignItems: "center", gap: 20, flex: 1, minWidth: 0 }}>
              {/* RIESGO DEL PERFIL */}
              <div>
                <div className="zm-stat-label">RIESGO DEL PERFIL</div>
                <div className="zm-stat-value">Muy bajo</div>
              </div>
              {/* PUNTOS VMC */}
              <div>
                <div className="zm-stat-label">PUNTOS VMC</div>
                <div className="zm-pts">
                  <StarIcon size={24} />
                  <span>500 pts</span>
                  <InfoIcon size={16} />
                </div>
              </div>
            </div>
            <ProfileButton>Historial</ProfileButton>
          </div>
        </div>

        {/* WalletBalanceCard mobile — 388×206, botón CTA morado */}
        <WalletBalanceCard className="zm-wallet" />

        {/* ActivityCard mobile — 388×221, mismo grid 2×2 de pills */}
        <ActivityCard className="zm-activity" />

        {/* Banner secundario — 388×120 */}
        <div
          data-slot="secondary-banner"
          style={{
            width: 388,
            height: 120,
            boxSizing: "border-box",
            borderRadius: 8,
            background: "#E9EAEC",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            fontFamily: "monospace",
            fontSize: 12,
            letterSpacing: "0.08em",
            color: "#9AA1AC",
          }}
        >
          SECONDARY BANNER
        </div>

        {/* OfferShelf mobile — RECOMENDADOS (2×2 grid) */}
        <div className="zm-shelf">
          <header style={{ padding: "0 8px" }}>
            <CardTitle title="RECOMENDADOS" subtitle="4 Ofertas" titleSize={16} subtitleSize={14} />
          </header>
          <div className="zm-shelf__grid">
            <OfferCard variant="live" name="Audi Q3" year={2026} price="US$ 9,999" imageSrc="/demo/bronco.jpg" elevated />
            <OfferCard variant="live" name="Audi Q3" year={2026} price="US$ 9,999" imageSrc="/demo/bronco.jpg" badge={<BadgeStatus variant="live" />} elevated />
            <OfferCard variant="negotiable" name="Audi Q3" year={2026} imageSrc="/demo/bronco.jpg" elevated />
            <OfferCard variant="live" name="Audi Q3" year={2026} price="US$ 9,999" imageSrc="/demo/bronco.jpg" elevated />
          </div>
        </div>

        {/* OfferShelf mobile — ME INTERESA (2×2 grid) */}
        <div className="zm-shelf">
          <header style={{ padding: "0 8px" }}>
            <CardTitle title="ME INTERESA" subtitle="4 Ofertas" titleSize={16} subtitleSize={14} />
          </header>
          <div className="zm-shelf__grid">
            <OfferCard variant="live" name="Audi Q3" year={2026} price="US$ 9,999" imageSrc="/demo/bronco.jpg" elevated />
            <OfferCard variant="live" name="Audi Q3" year={2026} price="US$ 9,999" imageSrc="/demo/bronco.jpg" badge={<BadgeStatus variant="live" />} elevated />
            <OfferCard variant="negotiable" name="Audi Q3" year={2026} imageSrc="/demo/bronco.jpg" elevated />
            <OfferCard variant="live" name="Audi Q3" year={2026} price="US$ 9,999" imageSrc="/demo/bronco.jpg" elevated />
          </div>
        </div>

        {/* CENTRO DE AYUDA — 388×116 */}
        <div
          data-slot="help-banner"
          style={{
            width: 388,
            height: 116,
            boxSizing: "border-box",
            borderRadius: 8,
            background: "#E9EAEC",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            fontFamily: "monospace",
            fontSize: 12,
            letterSpacing: "0.08em",
            color: "#9AA1AC",
          }}
        >
          CENTRO DE AYUDA
        </div>

      </div>
    </div>
  );

  return (
    <SidebarMobile open={menuOpen} onOpenChange={setMenuOpen} frameHeight={frameHeight}>
      {page}
    </SidebarMobile>
  );
}

"use client";

/**
 * UserProfileCard — Generado por Concorde
 * Fuente: Figma VOYAGER · "UserProfileCard" (nodo 2035:16581)
 *
 * Tarjeta de zona de usuario 766×140 (blanca, radius 16, drop shadow suave).
 * Dos filas internas de 734 de ancho separadas por un divisor #E1E3E2:
 *   1ª (52px): avatar (AvatarZone) + «¡Hola, {usuario}!»  ·······  «Tu perfil ›» (ProfileButton)
 *   2ª (40px): RIESGO DEL PERFIL / valor  +  PUNTOS VMC / ⭐ pts ⓘ  ···  «Historial ›» (ProfileButton)
 *
 * Figma manda en lo visual; Concorde compone los componentes existentes
 * (AvatarZone, ProfileButton, StarIcon) y aporta el layout + accesibilidad.
 */

import type { JSX, MouseEventHandler } from "react";
import AvatarZone from "@/concorde/components/AvatarZone";
import ProfileButton from "@/concorde/components/ProfileButton";
import StarIcon from "@/concorde/components/StarIcon";
import InfoIcon from "@/concorde/components/InfoIcon";

// ─── Types ────────────────────────────────────────────────────────────────────

export interface UserProfileCardProps {
  /** Usuario mostrado en «¡Hola, {usuario}!» (default "ZAEX5G"). */
  username?: string;
  /** Etiqueta de la 1ª estadística (default "RIESGO DEL PERFIL"). */
  riskLabel?: string;
  /** Valor de riesgo (default "Muy bajo"). */
  riskValue?: string;
  /** Etiqueta de la 2ª estadística (default "PUNTOS VMC"). */
  pointsLabel?: string;
  /** Puntos VMC (default "500 pts"). */
  points?: string;
  /** Acción / enlace del acceso «Tu perfil». */
  onProfile?: MouseEventHandler<HTMLElement>;
  profileHref?: string;
  /** Acción / enlace del acceso «Historial». */
  onHistory?: MouseEventHandler<HTMLElement>;
  historyHref?: string;
  className?: string;
}

// ─── Self-contained CSS ───────────────────────────────────────────────────────

const STYLE_ID = "concorde-userprofilecard-styles";

const STYLES = `
.upc {
  box-sizing: border-box;
  width: 766px;
  height: 140px;
  padding: 16px;
  border-radius: 16px;
  background: #ffffff;
  /* Drop shadow del filtro Figma (dilate 4 · blur 8 · negro 10%) */
  box-shadow: 0 0 8px 4px rgba(0,0,0,0.08);
  font-family: var(--vmc-font-display, "Plus Jakarta Sans", -apple-system, sans-serif);
}
.upc__inner {
  display: flex;
  flex-direction: column;
  justify-content: space-between;
  height: 100%;
}
/* ── Fila 1 (734×52) ── */
.upc__row1 {
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: 52px;
}
.upc__greet {
  display: flex;
  align-items: center;
  gap: 10px;
  min-width: 0;
}
.upc__hello {
  font-size: 18px;
  font-weight: 700;
  letter-spacing: -0.01em;
  line-height: 24px;
  white-space: nowrap;
  /* Texto con gradiente vault del Figma (paint1: #5F3ED8 → #340091 → #140046) */
  background: linear-gradient(168deg, #5F3ED8 0%, #340091 50%, #140046 100%);
  -webkit-background-clip: text;
  background-clip: text;
  color: transparent;
}
/* ── Divisor ── */
.upc__divider {
  height: 1px;
  background: #E1E3E2;
}
/* ── Fila 2 (734×40) ── */
.upc__row2 {
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: 40px;
}
.upc__stats {
  display: flex;
  align-items: center;
  gap: 56px;
}
.upc__stat {
  display: flex;
  flex-direction: column;
  gap: 2px;
}
.upc__stat-label {
  font-size: 10px;
  font-weight: 600;
  letter-spacing: 0.04em;
  text-transform: uppercase;
  color: #99A1AF;
  white-space: nowrap;
}
.upc__stat-value {
  font-size: 14px;
  font-weight: 700;
  line-height: 18px;
  white-space: nowrap;
}
.upc__stat-value--risk { color: #ED8936; }
.upc__points {
  display: flex;
  align-items: center;
  gap: 6px;
}
.upc__points-text { color: #3B1782; }
.upc__info { display: block; flex-shrink: 0; }
`;

let _stylesInjected = false;

// ─── Component ────────────────────────────────────────────────────────────────

export default function UserProfileCard({
  username = "ZAEX5G",
  riskLabel = "RIESGO DEL PERFIL",
  riskValue = "Muy bajo",
  pointsLabel = "PUNTOS VMC",
  points = "500 pts",
  onProfile,
  profileHref,
  onHistory,
  historyHref,
  className = "",
}: UserProfileCardProps): JSX.Element {
  if (typeof document !== "undefined" && !_stylesInjected) {
    if (!document.getElementById(STYLE_ID)) {
      const el = document.createElement("style");
      el.id = STYLE_ID;
      el.textContent = STYLES;
      document.head.appendChild(el);
    }
    _stylesInjected = true;
  }

  return (
    <>
      <style id={`${STYLE_ID}-ssr`} suppressHydrationWarning dangerouslySetInnerHTML={{ __html: STYLES }} />
      <section className={["upc", className].filter(Boolean).join(" ")} data-component="user-profile-card">
        <div className="upc__inner">
          {/* Fila 1 — saludo + acceso al perfil */}
          <div className="upc__row1">
            <div className="upc__greet">
              <AvatarZone size="md" title={`Avatar de ${username}`} />
              <span className="upc__hello">{`¡Hola, ${username}!`}</span>
            </div>
            <ProfileButton href={profileHref} onClick={onProfile} aria-label="Tu perfil">
              Tu perfil
            </ProfileButton>
          </div>

          {/* Divisor */}
          <div className="upc__divider" role="separator" aria-hidden="true" />

          {/* Fila 2 — estadísticas + historial */}
          <div className="upc__row2">
            <div className="upc__stats">
              <div className="upc__stat">
                <span className="upc__stat-label">{riskLabel}</span>
                <span className="upc__stat-value upc__stat-value--risk">{riskValue}</span>
              </div>
              <div className="upc__stat">
                <span className="upc__stat-label">{pointsLabel}</span>
                <span className="upc__points">
                  {/* StarIcon usa viewBox 28 con padding de sombra: el badge ocupa
                      16/28 → size 24 lo deja en ~16px, igual que el InfoIcon (16). */}
                  <StarIcon size={24} />
                  <span className="upc__stat-value upc__points-text">{points}</span>
                  <InfoIcon className="upc__info" title="Más información sobre los puntos VMC" />
                </span>
              </div>
            </div>
            <ProfileButton href={historyHref} onClick={onHistory} aria-label="Historial">
              Historial
            </ProfileButton>
          </div>
        </div>
      </section>
    </>
  );
}

"use client";

/**
 * AvatarZone — Generado por Concorde
 * Fuente: Figma VOYAGER · "Avatar Zone" (nodo 2035:16583)
 *
 * Avatar circular 32×32: relleno gradiente naranja (#FF9639 → #EF852E → #BE3D00)
 * con silueta de persona blanca centrada. Tamaño personalizable:
 * "sm" (24px) · "md" (32px) · o número de px.
 */

import { useId } from "react";
import type { JSX } from "react";

// ─── Types ────────────────────────────────────────────────────────────────────

export type AvatarZoneSize = "sm" | "md";

export interface AvatarZoneProps {
  /** Tamaño: "sm"=24px · "md"=32px · o número de px (default "md") */
  size?: AvatarZoneSize | number;
  /** Texto accesible — si se omite, el avatar es decorativo (aria-hidden) */
  title?: string;
  className?: string;
}

const SIZE_PX: Record<AvatarZoneSize, number> = { sm: 24, md: 32 };

const CIRCLE_PATH =
  "M0 16C0 7.16344 7.16344 0 16 0C24.8366 0 32 7.16344 32 16C32 24.8366 24.8366 32 16 32C7.16344 32 0 24.8366 0 16Z";

// ─── Component ────────────────────────────────────────────────────────────────

export default function AvatarZone({ size = "md", title, className = "" }: AvatarZoneProps): JSX.Element {
  const uid = useId().replace(/:/g, "-");
  const px = typeof size === "number" ? size : SIZE_PX[size];

  return (
    <svg
      width={px}
      height={px}
      viewBox="0 0 32 32"
      fill="none"
      className={className}
      role={title ? "img" : undefined}
      aria-hidden={title ? undefined : true}
      aria-label={title}
    >
      {title ? <title>{title}</title> : null}
      <g clipPath={`url(#${uid}-c0)`}>
        <path d={CIRCLE_PATH} fill={`url(#${uid}-bg)`} />
        <g clipPath={`url(#${uid}-c1)`}>
          <path
            d="M19.5412 11.36C19.5412 9.52 17.9765 8 16 8C14.0235 8 12.5412 9.52 12.5412 11.36C12.5412 13.28 14.0235 14.8 16 14.8C17.9765 14.8 19.5412 13.28 19.5412 11.36ZM9 20.4C10.4824 22.56 13.1176 24 16 24C18.8824 24 21.5176 22.56 23 20.4C23 18.16 18.3059 16.88 16 16.88C13.6941 16.88 9 18.16 9 20.4Z"
            fill="white"
          />
        </g>
      </g>
      <defs>
        <linearGradient id={`${uid}-bg`} x1="5.42742" y1="-16.8777" x2="43.7544" y2="-4.5528" gradientUnits="userSpaceOnUse">
          <stop stopColor="#FF9639" />
          <stop offset="0.5" stopColor="#EF852E" />
          <stop offset="1" stopColor="#BE3D00" />
        </linearGradient>
        <clipPath id={`${uid}-c0`}>
          <path d={CIRCLE_PATH} fill="white" />
        </clipPath>
        <clipPath id={`${uid}-c1`}>
          <rect width="24" height="24" fill="white" transform="translate(4 4)" />
        </clipPath>
      </defs>
    </svg>
  );
}

"use client";

/**
 * ProfileButton — Generado por Concorde
 * Fuente: Figma VOYAGER · "ProfileButton" (Status=Default|Hover|Pressed)
 * Nodos: 1274:5029 (default) · 1274:3989 (hover) · 1287:5144 (pressed)
 * Sincronizado: 2026-06-12
 *
 * Botón de navegación a perfil: label morado + círculo con chevron.
 * Figma manda en lo visual (colores/dimensiones); Concorde manda en la interacción
 * (transición de relleno + lift en hover, reduced-motion).
 */

import type { JSX, MouseEventHandler, ReactNode } from "react";

// ─── Types ────────────────────────────────────────────────────────────────────

